const d = $input.first().json.data;
const body = $('Webhook Report Request').first().json.body;
const fmt = n => Number(n||0).toLocaleString('es-AR', {minimumFractionDigits: 2, maximumFractionDigits: 2});

const rows = (d.transactions || []).slice(0, 50).map(t =>
  `<tr><td>${t.date}</td><td>${t.emoji||''} ${t.category||'—'}</td><td>${t.description||''}</td><td>${t.payment_method||''}</td><td>${t.group_name||''}</td><td style="text-align:right">$${fmt(t.amount)}</td></tr>`
).join('');

const byCatRows = (d.by_category || []).map(c =>
  `<tr><td>${c.emoji||''} ${c.category||'—'}</td><td style="text-align:right">${c.n}</td><td style="text-align:right">$${fmt(c.total)}</td></tr>`
).join('');

const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>
body{font-family:'Helvetica',sans-serif;color:#222;padding:24px;font-size:12px}
h1{font-size:22px;margin:0 0 4px 0}
h2{font-size:15px;margin-top:24px;border-bottom:1px solid #ddd;padding-bottom:4px}
.summary{display:flex;gap:16px;margin:16px 0}
.card{background:#f6f6f6;padding:12px 16px;border-radius:8px;flex:1}
.card .v{font-size:18px;font-weight:600}
.card .l{font-size:11px;color:#666}
table{width:100%;border-collapse:collapse;margin-top:8px}
th,td{padding:6px 8px;border-bottom:1px solid #eee;text-align:left}
th{background:#fafafa;font-weight:600}
</style></head><body>
<h1>Reporte de gastos</h1>
<div style="color:#666">${d.period.start} → ${d.period.end}</div>
<div class="summary">
<div class="card"><div class="l">Total gastado</div><div class="v">$${fmt(d.totals.expense)}</div></div>
<div class="card"><div class="l">Ingresos</div><div class="v">$${fmt(d.totals.income)}</div></div>
<div class="card"><div class="l">Movimientos</div><div class="v">${d.totals.count}</div></div>
</div>
<h2>Por categoría</h2>
<table><thead><tr><th>Categoría</th><th style="text-align:right">N</th><th style="text-align:right">Total</th></tr></thead><tbody>${byCatRows}</tbody></table>
<h2>Movimientos (últimos 50)</h2>
<table><thead><tr><th>Fecha</th><th>Categoría</th><th>Descripción</th><th>Pago</th><th>Grupo</th><th style="text-align:right">Monto</th></tr></thead><tbody>${rows}</tbody></table>
<div style="margin-top:32px;color:#999;font-size:10px">Generado por Chefin Bot — ${new Date().toLocaleDateString('es-AR')}</div>
</body></html>`;

return [{ json: { html, phone: body.phone, instance: body.instance || 'chefin', start: d.period.start, end: d.period.end }}];

const item = $input.first();
const meta = $('Build HTML').first().json;
const bin = item.binary && item.binary.data;
if (!bin || !bin.data) {
  throw new Error('No PDF binary received from html2pdf — check HTML2PDF_API_KEY and the API response');
}
// n8n stores binary as base64 already in bin.data — Evolution API accepts the raw base64 string
const base64 = bin.data;
const fileName = `reporte-${meta.start}_${meta.end}.pdf`;
return [{ json: { ...meta, mediaBase64: base64, fileName }, binary: item.binary }];
